                    })}
                  </div>
                )}

                <div className="summary">
                  <div className="summary-row"><span className="summary-label">Service</span><span className="summary-value">{selectedService?.name}</span></div>
                  <div className="summary-row"><span className="summary-label">Stylist</span><span className="summary-value">{selectedStaff?.name||"Any available"}</span></div>
                  <div className="summary-row"><span className="summary-label">Date</span><span className="summary-value">{selDate?.toLocaleDateString("en-GB",{day:"numeric",month:"short",year:"numeric"})}</span></div>
                  <div className="summary-row"><span className="summary-label">Time</span><span className="summary-value">{selTime}</span></div>
                  <div className="summary-row"><span className="summary-label">{isPayAtSalon ? "Due Now" : selectedOption?.pct === 100 ? "Total" : "Deposit Due"}</span><span className="summary-value" style={{color:"#667eea",fontSize:18}}>┬ú{chargeAmount.toFixed(2)}{isPayAtSalon ? " (pay at salon)" : ""}</span></div>
                </div>

                <button className="btn" disabled={!canSubmit||submitting} onClick={handleProceedToPayment}>
                  {submitting?"Setting up payment...":"Proceed to Payment ΓåÆ"}
                </button>
              </>
            )}

            {/* Step 4: Stripe Payment */}
            {step===4 && clientSecret && (
              <>
                <button onClick={()=>setStep(3)} className="back-btn">ΓåÉ Back to Details</button>
                {STRIPE_KEY_MISSING && (
                  <div style={{ padding:"14px 16px",background:"#FEF2F2",borderRadius:12,border:"1px solid #FECACA",marginBottom:16,fontSize:13,color:"#DC2626",fontWeight:600 }}>
                    ΓÜá∩╕Å Online payments are not configured. Please contact the salon to pay in person.
                  </div>
                )}
                <h2>Secure Payment</h2>
                <div style={{padding:"14px 16px",background:"#F8FAFC",borderRadius:12,border:"1px solid #E2E8F0",marginBottom:20}}>
                  <div style={{fontSize:12,color:"#64748B",fontWeight:600,marginBottom:4}}>Paying for</div>
                  <div style={{fontSize:15,fontWeight:700,color:"#0F172A"}}>{selectedService?.name} at {salon?.name}</div>
                   <div style={{fontSize:13,color:"#667eea",fontWeight:700,marginTop:2}}>
                    ┬ú{chargeAmount.toFixed(2)}
                    {selectedOption && selectedOption.pct < 100 ? ` (${selectedOption.label})` : ""}
                   </div>
                </div>
                {paymentError && <div style={{padding:"12px 14px",background:"#FEF2F2",borderRadius:10,border:"1px solid #FECACA",color:"#EF4444",fontSize:13,fontWeight:600,marginBottom:16}}>ΓÜá∩╕Å {paymentError}</div>}
                <Elements stripe={stripePromise} options={{ clientSecret, appearance:{ theme:"stripe", variables:{ colorPrimary:"#667eea", borderRadius:"12px", fontFamily:"'Plus Jakarta Sans', system-ui, sans-serif" } } }}>
                  <CheckoutForm
                    amount={selectedService?.price||0}
                    chargeAmount={chargeAmount}
                    methodLabel={selectedOption?.label||"Pay"}
                    bookingId={bookingId}
                    onSuccess={()=>setStep(5)}
                    onError={msg=>setPaymentError(msg)}
                    slug={slug}
                    service={selectedService?.name||""}
                    date={selDate?.toLocaleDateString("en-GB",{day:"numeric",month:"short",year:"numeric"})||""}
                    time={selTime}
                    name={form.name}
                    salon={salon?.name||""}
                  />
                </Elements>
              </>
            )}

            {/* Step 5: Booking Confirmed (pay_at_salon) */}
            {step===5 && confirmedBooking && (
              <div style={{ textAlign: "center", padding: "8px 0 16px" }}>
                {/* Success icon */}
                <div style={{ width: 88, height: 88, borderRadius: "50%", background: "linear-gradient(135deg,#10B981 0%,#059669 100%)", display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 24px", boxShadow: "0 12px 32px rgba(16,185,129,0.35)" }}>
                  <span style={{ fontSize: 40 }}>Γ£ô</span>
                </div>

                <h2 style={{ fontSize: 28, fontWeight: 800, color: "#0F172A", letterSpacing: "-0.8px", marginBottom: 8 }}>Booking Confirmed!</h2>
                <p style={{ fontSize: 15, color: "#64748B", fontWeight: 500, marginBottom: 28 }}>We look forward to seeing you, {confirmedBooking.name}.</p>

                {/* Details card */}
                <div style={{ background: "linear-gradient(135deg,#F8FAFC 0%,#F1F5F9 100%)", borderRadius: 20, border: "2px solid #E2E8F0", padding: "24px 20px", textAlign: "left", marginBottom: 20 }}>
                  <div style={{ display: "flex", flexDirection: "column", gap: 0 }}>
                    {/* Service */}
                    <div style={{ display: "flex", alignItems: "center", gap: 14, padding: "14px 0", borderBottom: "1px solid #E2E8F0" }}>
                      <div style={{ width: 40, height: 40, borderRadius: 10, background: "linear-gradient(135deg,#667eea,#764ba2)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18, flexShrink: 0 }}>Γ£é∩╕Å</div>
                      <div>
                        <div style={{ fontSize: 12, color: "#94A3B8", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.5px" }}>Service</div>
                        <div style={{ fontSize: 16, fontWeight: 700, color: "#0F172A", marginTop: 2 }}>{confirmedBooking.service}</div>
                      </div>
                    </div>
                    {/* Date */}
                    <div style={{ display: "flex", alignItems: "center", gap: 14, padding: "14px 0", borderBottom: "1px solid #E2E8F0" }}>
                      <div style={{ width: 40, height: 40, borderRadius: 10, background: "linear-gradient(135deg,#667eea,#764ba2)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18, flexShrink: 0 }}>≡ƒôà</div>
                      <div>
                        <div style={{ fontSize: 12, color: "#94A3B8", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.5px" }}>Date</div>
                        <div style={{ fontSize: 16, fontWeight: 700, color: "#0F172A", marginTop: 2 }}>{confirmedBooking.date}</div>
                      </div>
                    </div>
                    {/* Time */}
                    <div style={{ display: "flex", alignItems: "center", gap: 14, padding: "14px 0", borderBottom: "1px solid #E2E8F0" }}>
                      <div style={{ width: 40, height: 40, borderRadius: 10, background: "linear-gradient(135deg,#667eea,#764ba2)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18, flexShrink: 0 }}>≡ƒòÉ</div>
                      <div>
                        <div style={{ fontSize: 12, color: "#94A3B8", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.5px" }}>Time</div>
                        <div style={{ fontSize: 16, fontWeight: 700, color: "#0F172A", marginTop: 2 }}>{confirmedBooking.time}</div>
                      </div>
                    </div>
                    {/* Payment */}
                    <div style={{ display: "flex", alignItems: "center", gap: 14, padding: "14px 0" }}>
                      <div style={{ width: 40, height: 40, borderRadius: 10, background: "linear-gradient(135deg,#10B981,#059669)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18, flexShrink: 0 }}>≡ƒÆ│</div>
                      <div>
                        <div style={{ fontSize: 12, color: "#94A3B8", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.5px" }}>Payment</div>
                        <div style={{ display: "flex", alignItems: "center", gap: 8, marginTop: 4 }}>
                          <span style={{ fontSize: 13, fontWeight: 700, color: "#10B981", background: "rgba(16,185,129,0.1)", padding: "4px 10px", borderRadius: 20, border: "1px solid rgba(16,185,129,0.2)" }}>Pay at Salon</span>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>

                {/* Confirmation note */}
                <p style={{ fontSize: 13, color: "#94A3B8", fontWeight: 500, lineHeight: 1.6 }}>A confirmation has been sent to your email and phone. Please arrive a few minutes early.</p>

                {/* Manage / Reschedule link */}
                {confirmedBooking?.apptId && (
                  <a href={`/reschedule/${confirmedBooking.apptId}`}
                    style={{ display: "inline-block", marginTop: 20, padding: "12px 24px", background: "#F1F5F9", color: "#475569", borderRadius: 12, textDecoration: "none", fontSize: 13, fontWeight: 700, border: "1.5px solid #E2E8F0" }}>
                    ≡ƒôà Manage / Reschedule Appointment
                  </a>
                )}
              </div>
            )}
          </div>
        </div>
      </div>
    </>
  );
}

"use client";
import { useState, useEffect } from "react";
import { supabase } from "../lib/supabase";

export default function BookPage() {
  const [salons, setSalons] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState("");

  useEffect(() => {
    const loadSalons = async () => {
      const { data, error } = await supabase
        .from("salons")
        .select("id, name, slug")
        .order("name");

      if (!error && data) {
        setSalons(data);
      }
      setLoading(false);
    };

    loadSalons();
  }, []);

  const filteredSalons = salons.filter(salon =>
    salon.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  if (loading) {
    return (
      <div style={{ minHeight: "100vh", background: "#F2F4F7", display: "flex", alignItems: "center", justifyContent: "center" }}>
        <div style={{ fontFamily: "Georgia, serif", fontSize: "24px", color: "#4F6EF7" }}>Loading...</div>
      </div>
    );
  }

  return (
    <div style={{ minHeight: "100vh", background: "#F2F4F7" }}>
      {/* Header */}
      <div style={{ background: "#fff", borderBottom: "0.5px solid #E8EAF0", padding: "32px 20px", textAlign: "center" }}>
        <div style={{ fontFamily: "Georgia, serif", fontSize: "32px", color: "#0F172A", marginBottom: "8px" }}>Book a Salon</div>
        <div style={{ fontSize: "16px", color: "#64748B", maxWidth: "600px", margin: "0 auto" }}>
          Find and book appointments at your favorite salons
        </div>
      </div>

      {/* Search */}
      <div style={{ padding: "32px 20px", maxWidth: "600px", margin: "0 auto" }}>
        <div style={{ background: "#fff", border: "0.5px solid #E8EAF0", borderRadius: "12px", padding: "20px" }}>
          <label style={{ fontSize: "14px", fontWeight: 500, color: "#0F172A", display: "block", marginBottom: "12px" }}>
            Search salons
          </label>
          <input
            type="text"
            placeholder="Enter salon name..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            style={{
              width: "100%",
              padding: "12px 16px",
              border: "0.5px solid #E8EAF0",
              borderRadius: "8px",
              fontSize: "16px",
              color: "#0F172A",
              outline: "none",
              boxSizing: "border-box"
            }}
          />
        </div>
      </div>

      {/* Salon List */}
      <div style={{ padding: "0 20px 32px", maxWidth: "600px", margin: "0 auto" }}>
        {filteredSalons.length === 0 ? (
          <div style={{ background: "#fff", borderRadius: "12px", padding: "48px", textAlign: "center", color: "#94A3B8" }}>
            {searchTerm ? "No salons found matching your search." : "No salons available yet."}
          </div>
        ) : (
          filteredSalons.map((salon) => (
            <a
              key={salon.id}
              href={`/book/${salon.slug}`}
              style={{
                display: "block",
                background: "#fff",
                border: "0.5px solid #E8EAF0",
                borderRadius: "12px",
                padding: "20px",
                marginBottom: "16px",
                textDecoration: "none",
                color: "#0F172A",
                transition: "all 0.2s ease"
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.borderColor = "#4F6EF7";
                e.currentTarget.style.boxShadow = "0 4px 12px rgba(79, 112, 247, 0.1)";
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.borderColor = "#E8EAF0";
                e.currentTarget.style.boxShadow = "none";
              }}
            >
              <div style={{ fontSize: "18px", fontWeight: 600, color: "#0F172A", marginBottom: "4px" }}>
                {salon.name}
              </div>
              <div style={{ fontSize: "14px", color: "#64748B" }}>
                Click to view services and book ΓåÆ
              </div>
            </a>
          ))
        )}
      </div>

      <div style={{ textAlign: "center", padding: "32px", fontSize: "12px", color: "#CBD5E1" }}>
        Powered by <span style={{ fontFamily: "Georgia, serif", color: "#4F6EF7" }}>feature</span>
      </div>
    </div>
  );
}

"use client";
import React, { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { supabase } from "../../lib/supabase";
import { getCurrentUserProfile } from "@/app/lib/auth";
import DashboardShell, { HamburgerBtn } from "../components/DashboardShell";
import { useToast } from "../components/Toast";

interface Automation {
  id?: string;
  type: string;
  is_active: boolean;
  channel: string;
  message: string;
  days_before: number;
  reward: string;
}

const DEFAULT_AUTOMATIONS: Automation[] = [
  {
    type: "birthday",
    is_active: false,
    channel: "whatsapp",
    message: "≡ƒÄé Happy Birthday {name}! As our special client, enjoy a FREE birthday treat at {salon} this month. Call us to book! ≡ƒÄë",
    days_before: 1,
    reward: "Free treatment",
  },
  {
    type: "winback",
    is_active: false,
    channel: "whatsapp",
    message: "Hi {name}! ≡ƒÆò We miss you at {salon}! It's been a while since your last visit. Come back and enjoy 15% off your next appointment. Book now!",
    days_before: 60,
    reward: "15% discount",
  },
  {
    type: "anniversary",
    is_active: false,
    channel: "whatsapp",
    message: "≡ƒÄë Happy 1-year anniversary with {salon}, {name}! Thank you for being a loyal client. Enjoy a special gift on us ΓÇö ask us when you visit!",
    days_before: 0,
    reward: "Anniversary gift",
  },
  {
    type: "referral",
    is_active: false,
    channel: "whatsapp",
    message: "Hi {name}! ≡ƒîƒ Love {salon}? Share with a friend and both of you get ┬ú10 off your next visit! Just ask them to mention your name when booking.",
    days_before: 0,
    reward: "┬ú10 for both",
  },
];

const TYPE_META: Record<string, { icon: string; label: string; desc: string; color: string }> = {
  birthday:    { icon: "≡ƒÄé", label: "Birthday Message",     desc: "Auto-send on client's birthday",           color: "#EC4899" },
  winback:     { icon: "≡ƒÆö", label: "Win-Back Campaign",    desc: "Re-engage clients who haven't visited",    color: "#F59E0B" },
  anniversary: { icon: "≡ƒÄë", label: "Loyalty Anniversary",  desc: "Celebrate 1 year with your salon",         color: "#6366F1" },
  referral:    { icon: "≡ƒöù", label: "Referral Prompt",      desc: "Encourage clients to refer friends",       color: "#10B981" },
};

export default function AutomationsPage() {
  const router = useRouter();
  const toast = useToast();
  const [salonId, setSalonId] = useState<string | null>(null);
  const [salonName, setSalonName] = useState("");
  const [automations, setAutomations] = useState<Automation[]>(DEFAULT_AUTOMATIONS);
  const [loading, setLoading] = useState(true);
  const [editing, setEditing] = useState<string | null>(null);

  useEffect(() => {
    const load = async () => {
      const profile = await getCurrentUserProfile();
      if (!profile?.salon) { router.push("/login"); return; }
      setSalonId(profile.salon.id);
      setSalonName(profile.salon.name);
      const { data } = await supabase.from("automations").select("*").eq("salon_id", profile.salon.id);
      if (data && data.length > 0) {
        // Merge saved with defaults
        const merged = DEFAULT_AUTOMATIONS.map(def => {
          const saved = data.find(d => d.type === def.type);
          return saved ? { ...def, ...saved } : def;
        });
        setAutomations(merged);
      }
      setLoading(false);
    };
    load();
  }, [router]);

  const save = async (automation: Automation) => {
    if (!salonId) return;
    const { error } = await supabase.from("automations").upsert({
      salon_id: salonId, type: automation.type, is_active: automation.is_active,
      channel: automation.channel, message: automation.message,
      days_before: automation.days_before, reward: automation.reward,
    }, { onConflict: "salon_id,type" });
    if (error) { toast.error("Failed to save"); return; }
    toast.success("Automation saved!");
    setEditing(null);
  };

  const toggleActive = async (type: string, current: boolean) => {
    setAutomations(p => p.map(a => a.type === type ? { ...a, is_active: !current } : a));
    if (salonId) {
      await supabase.from("automations").upsert({
        salon_id: salonId, type, is_active: !current,
        message: automations.find(a => a.type === type)?.message || "",
      }, { onConflict: "salon_id,type" });
      toast.success(current ? "Automation paused" : "Automation activated!");
    }
  };

  const update = (type: string, field: string, value: any) => {
    setAutomations(p => p.map(a => a.type === type ? { ...a, [field]: value } : a));
  };

  const Topbar = (
    <header style={{ background: "#fff", borderBottom: "1px solid #F1F5F9", padding: "0 24px", height: 66, display: "flex", alignItems: "center", justifyContent: "space-between", position: "sticky", top: 0, zIndex: 30, boxShadow: "0 1px 3px rgba(0,0,0,0.04)" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
        <HamburgerBtn onClick={() => {}} />
        <div>
          <div style={{ fontSize: 15, fontWeight: 800, color: "#0F172A" }}>≡ƒñû Automations</div>
          <div style={{ fontSize: 11.5, color: "#94A3B8", marginTop: 1 }}>Birthday, Win-back & Referral messages</div>
        </div>
      </div>
      <div style={{ display: "flex", alignItems: "center", gap: 8, padding: "6px 14px", background: "#ECFDF5", border: "1.5px solid #A7F3D0", borderRadius: 12 }}>
        <span style={{ fontSize: 12, fontWeight: 800, color: "#059669" }}>Γ£ô {automations.filter(a => a.is_active).length} Active</span>
      </div>
    </header>
  );

  if (loading) return <DashboardShell salonName={salonName} topbar={Topbar}><div style={{ padding: 40, textAlign: "center", color: "#94A3B8" }}>LoadingΓÇª</div></DashboardShell>;

  return (
    <DashboardShell salonName={salonName} topbar={Topbar}>
      <div style={{ padding: "28px 24px", maxWidth: 1000, margin: "0 auto" }}>

        {/* Info banner */}
        <div style={{ background: "linear-gradient(135deg,#EEF2FF,#F0FDF4)", border: "1.5px solid #C7D2FE", borderRadius: 16, padding: "16px 20px", marginBottom: 24, display: "flex", gap: 14, alignItems: "center" }}>
          <span style={{ fontSize: 28 }}>≡ƒñû</span>
          <div>
            <div style={{ fontSize: 14, fontWeight: 800, color: "#0F172A" }}>Automated Messages</div>
            <div style={{ fontSize: 13, color: "#475569", marginTop: 2, lineHeight: 1.5 }}>
              Set up once, send automatically. Use <strong>{"{name}"}</strong>, <strong>{"{salon}"}</strong>, <strong>{"{link}"}</strong> as variables. Messages are sent via your chosen channel.
