            return (
              <div key={auto.type} style={{ background: "#fff", border: `1.5px solid ${auto.is_active ? meta.color + "40" : "#F1F5F9"}`, borderRadius: 20, overflow: "hidden", boxShadow: "0 2px 8px rgba(0,0,0,0.03)", transition: "all 0.2s" }}>
                <div style={{ padding: "20px 24px", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                  <div style={{ display: "flex", gap: 14, alignItems: "center" }}>
                    <div style={{ width: 48, height: 48, borderRadius: 14, background: `${meta.color}15`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 22 }}>{meta.icon}</div>
                    <div>
                      <div style={{ fontSize: 15, fontWeight: 800, color: "#0F172A" }}>{meta.label}</div>
                      <div style={{ fontSize: 12.5, color: "#64748B", marginTop: 2 }}>{meta.desc}</div>
                      {auto.reward && <div style={{ fontSize: 11.5, fontWeight: 700, color: meta.color, marginTop: 4 }}>≡ƒÄü Reward: {auto.reward}</div>}
                    </div>
                  </div>
                  <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                    {auto.is_active && <span style={{ fontSize: 11, fontWeight: 800, padding: "3px 10px", borderRadius: 99, background: `${meta.color}18`, color: meta.color }}>ΓùÅ ACTIVE</span>}
                    <label style={{ position: "relative", width: 44, height: 24, cursor: "pointer", flexShrink: 0 }}>
                      <input type="checkbox" checked={auto.is_active} onChange={() => toggleActive(auto.type, auto.is_active)} style={{ opacity: 0, width: 0, height: 0 }} />
                      <span style={{ position: "absolute", inset: 0, background: auto.is_active ? meta.color : "#CBD5E1", borderRadius: 99, transition: "background 0.18s" }}>
                        <span style={{ position: "absolute", width: 16, height: 16, left: auto.is_active ? 24 : 4, top: 4, background: "#fff", borderRadius: "50%", transition: "left 0.18s", boxShadow: "0 1px 4px rgba(0,0,0,0.15)" }} />
                      </span>
                    </label>
                    <button onClick={() => setEditing(isEditing ? null : auto.type)} style={{ padding: "7px 14px", background: isEditing ? "#EEF2FF" : "#F8FAFC", border: `1.5px solid ${isEditing ? "#C7D2FE" : "#E2E8F0"}`, borderRadius: 10, fontSize: 12.5, fontWeight: 700, color: isEditing ? "#4F46E5" : "#475569", cursor: "pointer" }}>
                      {isEditing ? "Γ£ò Close" : "Γ£Å∩╕Å Edit"}
                    </button>
                  </div>
                </div>

                {/* Edit panel */}
                {isEditing && (
                  <div style={{ borderTop: "1px solid #F1F5F9", padding: "20px 24px", background: "#FAFAFA" }}>
                    <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
                      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}>
                        <div>
                          <label style={{ fontSize: 12, fontWeight: 700, color: "#475569", display: "block", marginBottom: 6 }}>Channel</label>
                          <select value={auto.channel} onChange={e => update(auto.type, "channel", e.target.value)} style={{ width: "100%", padding: "9px 12px", border: "1.5px solid #E2E8F0", borderRadius: 10, fontSize: 13, outline: "none", fontFamily: "inherit" }}>
                            <option value="whatsapp">≡ƒô▒ WhatsApp</option>
                            <option value="sms">≡ƒÆ¼ SMS</option>
                            <option value="email">≡ƒôº Email</option>
                          </select>
                        </div>
                        {auto.type === "winback" && (
                          <div>
                            <label style={{ fontSize: 12, fontWeight: 700, color: "#475569", display: "block", marginBottom: 6 }}>Trigger after (days inactive)</label>
                            <input type="number" value={auto.days_before} onChange={e => update(auto.type, "days_before", parseInt(e.target.value))}
                              style={{ width: "100%", padding: "9px 12px", border: "1.5px solid #E2E8F0", borderRadius: 10, fontSize: 13, outline: "none", fontFamily: "inherit", boxSizing: "border-box" }} />
                          </div>
                        )}
                        <div>
                          <label style={{ fontSize: 12, fontWeight: 700, color: "#475569", display: "block", marginBottom: 6 }}>Reward (optional)</label>
                          <input value={auto.reward} onChange={e => update(auto.type, "reward", e.target.value)} placeholder="e.g. 10% off"
                            style={{ width: "100%", padding: "9px 12px", border: "1.5px solid #E2E8F0", borderRadius: 10, fontSize: 13, outline: "none", fontFamily: "inherit", boxSizing: "border-box" }} />
                        </div>
                      </div>
                      <div>
                        <label style={{ fontSize: 12, fontWeight: 700, color: "#475569", display: "block", marginBottom: 6 }}>Message</label>
                        <textarea value={auto.message} onChange={e => update(auto.type, "message", e.target.value)} rows={3}
                          style={{ width: "100%", padding: "10px 13px", border: "1.5px solid #E2E8F0", borderRadius: 10, fontSize: 13.5, fontFamily: "inherit", outline: "none", resize: "vertical", boxSizing: "border-box", lineHeight: 1.6 }} />
                        <div style={{ fontSize: 11, color: "#94A3B8", marginTop: 4 }}>Variables: {"{name}"}, {"{salon}"}, {"{link}"}</div>
                      </div>
                    </div>
                    <button onClick={() => save(auto)} style={{ marginTop: 14, padding: "10px 24px", background: `linear-gradient(135deg,${meta.color},${meta.color}cc)`, border: "none", borderRadius: 12, fontSize: 13.5, fontWeight: 700, color: "#fff", cursor: "pointer", boxShadow: `0 4px 14px ${meta.color}40` }}>Save Automation</button>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>
    </DashboardShell>
  );
}

"use client";
import { useEffect, useState, useCallback, useMemo } from "react";
import { useRouter } from "next/navigation";
import { supabase } from "../../lib/supabase";
import DashboardShell, { HamburgerBtn } from "../components/DashboardShell";
import Modal, { FormGroup, Input, Select, ModalActions, BtnPrimary, BtnSecondary } from "../components/Modal";
import EmptyState from "../components/EmptyState";
import { SkeletonDashboard } from "../components/SkeletonLoader";
import { useToast } from "../components/Toast";
import type { Appointment, Service } from "../../types";

type StaffItem = { id: string; name: string };

const STATUS_COLORS: Record<string, { bg: string; color: string; border: string }> = {
  confirmed:  { bg: "var(--green-light)",  color: "var(--green)",  border: "var(--green-pale)" },
  pending:    { bg: "var(--indigo-light)", color: "var(--indigo)", border: "var(--indigo-pale)" },
  cancelled:  { bg: "var(--red-light)",    color: "var(--red)",    border: "var(--red-pale)" },
  completed:  { bg: "#F0FDF4",             color: "#059669",       border: "#A7F3D0" },
  no_show:    { bg: "#FFF7ED",             color: "#D97706",       border: "#FDE68A" },
};

function StatusPill({ status }: { status: string }) {
  const s = STATUS_COLORS[status] || STATUS_COLORS.pending;
  return <span style={{ fontSize: 10.5, fontWeight: 700, padding: "3px 9px", borderRadius: 99, background: s.bg, color: s.color, border: `1px solid ${s.border}` }}>{status}</span>;
}

const EMPTY_FORM = { client_name: "", client_email: "", client_phone: "", staff_id: "", service_id: "", date_time: "", status: "pending" };

export default function BookingsPage() {
  const router = useRouter();
  const toast = useToast();
  const [salon, setSalon] = useState<any>(null);
  const [appointments, setAppointments] = useState<Appointment[]>([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState("All");
  const [view, setView] = useState<"table"|"calendar">("table");
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string|null>(null);
  const [formData, setFormData] = useState(EMPTY_FORM);
  const [staff, setStaff] = useState<StaffItem[]>([]);
  const [services, setServices] = useState<Service[]>([]);
  const [weekOffset, setWeekOffset] = useState(0);
  const [search, setSearch] = useState("");
  const [sendingEmail, setSendingEmail] = useState(false);

  useEffect(() => {
    const load = async () => {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) { router.push("/login"); return; }
      const { data: salonData } = await supabase.from("salons").select("*").eq("owner_id", user.id).single();
      setSalon(salonData);
      if (salonData) {
        const [{ data: appts }, { data: staffData }, { data: svcs }] = await Promise.all([
          supabase.from("appointments").select("*, services(name,price), staff(name)").eq("salon_id", salonData.id).order("date_time", { ascending: true }),
          supabase.from("staff").select("id,name").eq("salon_id", salonData.id),
          supabase.from("services").select("*").eq("salon_id", salonData.id),
        ]);
        setAppointments(appts || []);
        setStaff(staffData || []);
        setServices(svcs || []);
      }
      setLoading(false);
    };
    load();
  }, [router]);

  const reloadAppts = useCallback(async () => {
    if (!salon) return;
    const { data } = await supabase.from("appointments").select("*, services(name,price), staff(name)").eq("salon_id", salon.id).order("date_time", { ascending: true });
    setAppointments(data || []);
  }, [salon]);

  const handleSubmit = useCallback(async (e: React.FormEvent) => {
    e.preventDefault();
    if (!salon) return;
    if (editingId) {
      const { error } = await supabase.from("appointments").update({ client_name: formData.client_name, client_email: formData.client_email, client_phone: formData.client_phone, staff_id: formData.staff_id || null, service_id: formData.service_id, date_time: formData.date_time, status: formData.status }).eq("id", editingId);
      if (error) { toast.error("Failed to update booking"); return; }
      toast.success("Booking updated!");
    } else {
      // Insert and get the new row's ID
      const { data: inserted, error } = await supabase
        .from("appointments")
        .insert({ salon_id: salon.id, client_name: formData.client_name, client_email: formData.client_email, client_phone: formData.client_phone, staff_id: formData.staff_id || null, service_id: formData.service_id, date_time: formData.date_time, status: formData.status })
        .select("id")
        .single();
      if (error) { toast.error("Failed to create booking"); return; }

      // Send confirmation email + WhatsApp to client (if email provided)
      if (formData.client_email && inserted?.id) {
        setSendingEmail(true);
        try {
          const appUrl = window.location.origin;
          await fetch(`${appUrl}/api/send-confirmation`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ appointmentId: inserted.id }),
          });
        } catch { /* non-fatal */ }
        setSendingEmail(false);
      }
      toast.success("Booking created! Confirmation sent to client.");
    }
    setFormData(EMPTY_FORM);
    setShowForm(false);
    setEditingId(null);
    await reloadAppts();
  }, [salon, editingId, formData, toast, reloadAppts]);

  const handleEdit = useCallback((a: Appointment) => {
    setEditingId(a.id);
    setFormData({ client_name: a.client_name || "", client_email: a.client_email || "", client_phone: a.client_phone || "", staff_id: a.staff_id || "", service_id: a.service_id || "", date_time: a.date_time ? a.date_time.slice(0,16) : "", status: a.status || "pending" });
    setShowForm(true);
  }, []);

  const handleDelete = useCallback(async (id: string) => {
    if (!window.confirm("Delete this booking? This cannot be undone.")) return;
    const { error } = await supabase.from("appointments").delete().eq("id", id);
    if (error) { toast.error("Failed to delete"); return; }
    toast.success("Booking deleted");
    await reloadAppts();
  }, [toast, reloadAppts]);

  const now = new Date();
  const filtered = useMemo(() => {
    let list = appointments;
    if (activeTab === "Today")     list = list.filter(a => new Date(a.date_time).toDateString() === now.toDateString());
    else if (activeTab === "Upcoming")  list = list.filter(a => new Date(a.date_time) > now && a.status !== "cancelled" && a.status !== "completed" && a.status !== "no_show");
    else if (activeTab === "Completed") list = list.filter(a => a.status === "completed");
    else if (activeTab === "Cancelled") list = list.filter(a => a.status === "cancelled" || a.status === "no_show");
    if (search) list = list.filter(a => a.client_name?.toLowerCase().includes(search.toLowerCase()) || (a.services as any)?.name?.toLowerCase().includes(search.toLowerCase()));
    return list;
  }, [appointments, activeTab, search, now]);

  const getWeekDays = useCallback(() => {
    const d = new Date(); d.setDate(d.getDate() - d.getDay() + weekOffset * 7);
    return Array.from({ length: 7 }, (_, i) => { const x = new Date(d); x.setDate(d.getDate() + i); return x; });
  }, [weekOffset]);

  const weekDays = getWeekDays();

  if (loading) return <DashboardShell salonName=""><SkeletonDashboard /></DashboardShell>;

  const Topbar = (
    <header style={{ background: "#fff", borderBottom: "1px solid var(--border)", padding: "0 20px", height: 58, display: "flex", alignItems: "center", justifyContent: "space-between", position: "sticky", top: 0, zIndex: 30, gap: 12, flexWrap: "wrap" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
        <HamburgerBtn onClick={() => {}} />
        <div>
          <div style={{ fontSize: 15, fontWeight: 700, color: "var(--text-1)", letterSpacing: "-0.3px" }}>Bookings</div>
          <div style={{ fontSize: 11.5, color: "var(--text-3)" }}>{appointments.length} total appointments</div>
        </div>
      </div>
      <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
        <div style={{ display: "flex", background: "var(--slate-100)", borderRadius: 8, padding: 3 }}>
          {(["table","calendar"] as const).map(v => (
            <button key={v} onClick={() => setView(v)} style={{ padding: "5px 14px", borderRadius: 6, border: "none", background: view === v ? "#fff" : "transparent", color: view === v ? "var(--text-1)" : "var(--text-3)", fontSize: 12, cursor: "pointer", fontWeight: view === v ? 600 : 400, boxShadow: view === v ? "var(--shadow-xs)" : "none", transition: "all 0.12s" }}>
              {v === "table" ? "Table" : "Calendar"}
            </button>
          ))}
        </div>
        <button onClick={() => { setShowForm(true); setEditingId(null); setFormData(EMPTY_FORM); }} style={{ background: "var(--indigo)", color: "#fff", fontSize: 13, fontWeight: 600, padding: "8px 16px", borderRadius: "var(--r-sm)", border: "none", cursor: "pointer", boxShadow: "var(--shadow-indigo)", whiteSpace: "nowrap", transition: "all 0.14s" }}
          onMouseEnter={e => { e.currentTarget.style.background = "var(--indigo-dark)"; }}
          onMouseLeave={e => { e.currentTarget.style.background = "var(--indigo)"; }}
        >+ New Booking</button>
      </div>
    </header>
  );

  return (
    <DashboardShell salonName={salon?.name} topbar={Topbar}>
      <div style={{ padding: "24px 20px" }}>

        {/* Search + Tabs bar */}
        <div style={{ display: "flex", gap: 10, alignItems: "center", marginBottom: 16, flexWrap: "wrap" }}>
          <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search by client or service..." style={{ flex: 1, minWidth: 160, padding: "9px 13px", border: "1px solid var(--border-2)", borderRadius: "var(--r-sm)", fontSize: 13.5, fontFamily: "var(--font)", outline: "none", color: "var(--text-1)" }}
            onFocus={e => { e.currentTarget.style.borderColor = "var(--indigo)"; e.currentTarget.style.boxShadow = "0 0 0 3px rgba(99,102,241,0.12)"; }}
            onBlur={e => { e.currentTarget.style.borderColor = "var(--border-2)"; e.currentTarget.style.boxShadow = "none"; }}
          />
          <div style={{ display: "flex", gap: 2, background: "var(--slate-100)", padding: 3, borderRadius: 8, flexWrap: "wrap" }}>
            {["All","Today","Upcoming","Completed","Cancelled"].map(t => (
              <button key={t} onClick={() => setActiveTab(t)} style={{ fontSize: 12, padding: "5px 10px", borderRadius: 6, border: "none", background: activeTab === t ? "#fff" : "transparent", color: activeTab === t ? "var(--indigo)" : "var(--text-3)", cursor: "pointer", fontWeight: activeTab === t ? 700 : 500, boxShadow: activeTab === t ? "var(--shadow-xs)" : "none", transition: "all 0.12s" }}>{t}</button>
            ))}
          </div>
        </div>

        {view === "table" ? (
          <div style={{ background: "#fff", border: "1px solid var(--border)", borderRadius: "var(--r-lg)", overflow: "hidden" }}>
            {filtered.length === 0 ? (
              <EmptyState icon="≡ƒôà" title="No bookings found" description={search ? "Try a different search term" : "Create your first booking"} action={{ label: "+ New Booking", onClick: () => setShowForm(true) }} />
            ) : (
              <>
                <div style={{ overflowX: "auto" }}>
                  <table style={{ width: "100%", borderCollapse: "collapse", minWidth: 600 }}>
                    <thead>
                      <tr style={{ background: "var(--slate-50)" }}>
                        {["Status","Client","Service","Staff","Date & Time","Amount","Notes","Actions"].map(h => (
                          <th key={h} style={{ fontSize: 10.5, fontWeight: 700, color: "var(--text-3)", textAlign: "left", padding: "10px 18px", letterSpacing: "0.5px", textTransform: "uppercase", borderBottom: "1px solid var(--border)" }}>{h}</th>
                        ))}
                      </tr>
                    </thead>
                    <tbody>
                      {filtered.map(a => (
                        <tr key={a.id}
                          onMouseEnter={e => { (e.currentTarget as HTMLTableRowElement).style.background = "var(--slate-50)"; }}
                          onMouseLeave={e => { (e.currentTarget as HTMLTableRowElement).style.background = "transparent"; }}
                          style={{ transition: "background 0.1s" }}
                        >
                          <td style={{ padding: "12px 18px", borderBottom: "1px solid var(--slate-100)" }}><StatusPill status={a.status} /></td>
                          <td style={{ padding: "12px 18px", borderBottom: "1px solid var(--slate-100)", fontSize: 13, fontWeight: 600, color: "var(--text-1)" }}>{a.client_name}</td>
                          <td style={{ padding: "12px 18px", borderBottom: "1px solid var(--slate-100)", fontSize: 13, color: "var(--text-2)" }}>{(a as any).services?.name || <span style={{color:"var(--text-3)",opacity:.5}}>ΓÇö</span>}</td>
                          <td style={{ padding: "12px 18px", borderBottom: "1px solid var(--slate-100)", fontSize: 13, color: "var(--text-3)" }}>{(a as any).staff?.name || <span style={{fontSize:11,color:"var(--text-3)",opacity:.5}}>Any</span>}</td>
                          <td style={{ padding: "12px 18px", borderBottom: "1px solid var(--slate-100)", fontSize: 13, color: "var(--text-2)" }}>{new Date(a.date_time).toLocaleString("en-GB", { day: "numeric", month: "short", year: "numeric", hour: "2-digit", minute: "2-digit" })}</td>
                          <td style={{ padding: "12px 18px", borderBottom: "1px solid var(--slate-100)", fontSize: 13, fontWeight: 700, color: "var(--green)" }}>{(a as any).services?.price ? `┬ú${(a as any).services.price}` : <span style={{color:"var(--text-3)",opacity:.5}}>ΓÇö</span>}</td>
                          <td style={{ padding: "12px 18px", borderBottom: "1px solid var(--slate-100)", fontSize: 12, color: "var(--text-3)", maxWidth: 130 }}>
                            {(a as any).notes
                              ? <span title={(a as any).notes} style={{ display:"block",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",maxWidth:120,cursor:"help" }}>{(a as any).notes}</span>
                              : <span style={{opacity:.3}}>ΓÇö</span>}
                          </td>
                          <td style={{ padding: "12px 18px", borderBottom: "1px solid var(--slate-100)", whiteSpace: "nowrap" }}>
                            <button onClick={() => handleEdit(a)} style={{ color: "var(--indigo)", background: "none", border: "none", cursor: "pointer", fontSize: 12, fontWeight: 600, marginRight: 8, fontFamily: "var(--font)" }}>Edit</button>
                            {a.status !== "completed" && a.status !== "cancelled" && (
                              <button onClick={async () => {
                                await supabase.from("appointments").update({ status: "completed" }).eq("id", a.id);
                                await reloadAppts();
                                toast.success("Marked as complete Γ£ô");
                              }} style={{ color: "#059669", background: "none", border: "none", cursor: "pointer", fontSize: 12, fontWeight: 600, marginRight: 8, fontFamily: "var(--font)" }}>Γ£ô Done</button>
                            )}
                            {a.status !== "no_show" && a.status !== "cancelled" && a.status !== "completed" && (
                              <button onClick={async () => {
                                await supabase.from("appointments").update({ status: "no_show" }).eq("id", a.id);
                                await reloadAppts();
                                toast.success("Marked as no-show");
                              }} style={{ color: "#D97706", background: "none", border: "none", cursor: "pointer", fontSize: 12, fontWeight: 600, marginRight: 8, fontFamily: "var(--font)" }}>No-show</button>
                            )}
                            <button onClick={() => handleDelete(a.id)} style={{ color: "var(--red)", background: "none", border: "none", cursor: "pointer", fontSize: 12, fontWeight: 600, fontFamily: "var(--font)" }}>Delete</button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </>
            )}
          </div>
        ) : (
          /* Calendar View */
          <div style={{ background: "#fff", border: "1px solid var(--border)", borderRadius: "var(--r-lg)", overflow: "hidden" }}>
            <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "14px 18px", borderBottom: "1px solid var(--border)" }}>
              <button onClick={() => setWeekOffset(w => w - 1)} style={{ border: "1px solid var(--border)", background: "#fff", borderRadius: "var(--r-sm)", padding: "5px 12px", cursor: "pointer", fontSize: 14, color: "var(--text-2)" }}>∩┐╜</button>
              <div style={{ fontSize: 13, fontWeight: 600, color: "var(--text-1)" }}>
                {weekDays[0].toLocaleDateString("en-GB", { day: "numeric", month: "short" })} ∩┐╜ {weekDays[6].toLocaleDateString("en-GB", { day: "numeric", month: "short", year: "numeric" })}
              </div>
              <div style={{ display: "flex", gap: 6 }}>
                <button onClick={() => setWeekOffset(0)} style={{ border: "1px solid var(--indigo-pale)", background: "var(--indigo-light)", borderRadius: "var(--r-sm)", padding: "5px 12px", cursor: "pointer", fontSize: 12, color: "var(--indigo)", fontWeight: 600 }}>Today</button>
                <button onClick={() => setWeekOffset(w => w + 1)} style={{ border: "1px solid var(--border)", background: "#fff", borderRadius: "var(--r-sm)", padding: "5px 12px", cursor: "pointer", fontSize: 14, color: "var(--text-2)" }}>∩┐╜</button>
              </div>
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(7,1fr)", borderBottom: "1px solid var(--border)", overflowX: "auto" }}>
              {weekDays.map((day, i) => {
                const isToday = day.toDateString() === new Date().toDateString();
                return (
                  <div key={i} style={{ padding: "10px 8px", textAlign: "center", borderRight: i < 6 ? "1px solid var(--border)" : "none" }}>
                    <div style={{ fontSize: 10, color: "var(--text-3)", marginBottom: 4, textTransform: "uppercase", letterSpacing: "0.5px" }}>
                      {["Sun","Mon","Tue","Wed","Thu","Fri","Sat"][day.getDay()]}
                    </div>
                    <div style={{ width: 28, height: 28, borderRadius: "50%", background: isToday ? "var(--indigo)" : "transparent", color: isToday ? "#fff" : "var(--text-1)", fontSize: 13, fontWeight: isToday ? 700 : 500, display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto" }}>
                      {day.getDate()}
                    </div>
                  </div>
                );
              })}
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(7,1fr)", minHeight: 280, overflowX: "auto" }}>
              {weekDays.map((day, i) => {
                const dayAppts = appointments.filter(a => new Date(a.date_time).toDateString() === day.toDateString());
                return (
                  <div key={i} style={{ padding: 6, borderRight: i < 6 ? "1px solid var(--border)" : "none", minHeight: 200 }}>
                    {dayAppts.map(a => (
                      <div key={a.id} onClick={() => handleEdit(a)} style={{ background: "var(--indigo-light)", borderRadius: 6, padding: "5px 7px", marginBottom: 4, cursor: "pointer", borderLeft: "3px solid var(--indigo)", transition: "all 0.12s" }}
                        onMouseEnter={e => { e.currentTarget.style.background = "var(--indigo-pale)"; }}
                        onMouseLeave={e => { e.currentTarget.style.background = "var(--indigo-light)"; }}
                      >
                        <div style={{ fontSize: 10.5, fontWeight: 600, color: "var(--text-1)" }}>{new Date(a.date_time).toLocaleTimeString("en-GB", { hour: "2-digit", minute: "2-digit" })}</div>
                        <div style={{ fontSize: 10.5, color: "var(--indigo)", fontWeight: 500 }}>{a.client_name}</div>
                        <div style={{ fontSize: 10, color: "var(--text-3)" }}>{a.services?.name}</div>
                      </div>
                    ))}
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </div>

      {/* Booking Form Modal */}
      <Modal open={showForm} onClose={() => { setShowForm(false); setEditingId(null); }} title={editingId ? "Edit Booking" : "New Booking"}>
        <form onSubmit={handleSubmit}>
          <FormGroup label="Client Name *"><Input placeholder="Sarah Johnson" value={formData.client_name} onChange={e => setFormData({ ...formData, client_name: e.target.value })} required /></FormGroup>
          <FormGroup label="Email"><Input type="email" placeholder="sarah@email.com" value={formData.client_email} onChange={e => setFormData({ ...formData, client_email: e.target.value })} /></FormGroup>
          <FormGroup label="Phone"><Input placeholder="+44 7700 900000" value={formData.client_phone} onChange={e => setFormData({ ...formData, client_phone: e.target.value })} /></FormGroup>
          <FormGroup label="Date & Time *"><Input type="datetime-local" value={formData.date_time} onChange={e => setFormData({ ...formData, date_time: e.target.value })} required /></FormGroup>
          <FormGroup label="Service"><Select value={formData.service_id} onChange={e => setFormData({ ...formData, service_id: e.target.value })}><option value="">Select service</option>{services.map(s => <option key={s.id} value={s.id}>{s.name} - {s.price}</option>)}</Select></FormGroup>
          <FormGroup label="Staff"><Select value={formData.staff_id} onChange={e => setFormData({ ...formData, staff_id: e.target.value })}><option value="">Any Available Staff</option>{staff.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}</Select></FormGroup>
          <FormGroup label="Status"><Select value={formData.status} onChange={e => setFormData({ ...formData, status: e.target.value })}><option value="pending">Pending</option><option value="confirmed">Confirmed</option><option value="completed">Γ£ô Completed</option><option value="no_show">≡ƒÆñ No-show</option><option value="cancelled">Cancelled</option></Select></FormGroup>
          {!editingId && formData.client_email && (
            <p style={{ fontSize: 12, color: "#059669", margin: "0 0 12px", fontWeight: 500 }}>Γ£ë∩╕Å Confirmation email will be sent to {formData.client_email}</p>
          )}
          <ModalActions><BtnSecondary type="button" onClick={() => { setShowForm(false); setEditingId(null); }}>Cancel</BtnSecondary><BtnPrimary type="submit" disabled={sendingEmail}>{sendingEmail ? "Sending confirmationΓÇª" : editingId ? "Update" : "Create Booking"}</BtnPrimary></ModalActions>
        </form>
      </Modal>
    </DashboardShell>
  );
}

"use client";
import React, { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { supabase } from "../../lib/supabase";
import { getCurrentUserProfile } from "@/app/lib/auth";
import DashboardShell, { HamburgerBtn } from "../components/DashboardShell";
import { useToast } from "../components/Toast";
import FeatureGate from "../components/FeatureGate";

interface BroadcastMsg {
  id: string;
  title: string;
  message: string;
  channel: "whatsapp" | "sms" | "email";
  recipient_count: number;
  status: string;
  created_at: string;
}

const TEMPLATES = [
  { label: "≡ƒÄë Special Offer", message: "Hi {name}! ≡ƒîƒ We have a special offer just for you at {salon}. Book this week and get 20% off any service. Book now: {link}" },
  { label: "≡ƒÄé Birthday Wish", message: "Happy Birthday {name}! ≡ƒÄé As our valued client, enjoy a FREE birthday treatment this month at {salon}. Call us to book!" },
  { label: "≡ƒôà Appointment Reminder", message: "Hi {name}, just a reminder that {salon} is open and ready to serve you. Book your next appointment: {link}" },
  { label: "Γ¡É Review Request", message: "Hi {name}! Thank you for visiting {salon}. We'd love to hear your feedback. Please leave us a review: {link}" },
  { label: "≡ƒÄü Loyalty Reward", message: "Hi {name}! ≡ƒÄü You've earned enough loyalty points for a free reward at {salon}. Come in and claim it today!" },
];

function BroadcastContent() {
  const router = useRouter();
  const toast = useToast();
  const [salonId, setSalonId] = useState<string | null>(null);
  const [salonName, setSalonName] = useState("");
  const [salonSlug, setSalonSlug] = useState("");
  const [history, setHistory] = useState<BroadcastMsg[]>([]);
  const [clients, setClients] = useState<{ name: string; phone: string; email: string }[]>([]);
  const [loading, setLoading] = useState(true);
  const [form, setForm] = useState({ title: "", message: "", channel: "whatsapp" as "whatsapp"|"sms"|"email", filter: "all" as "all"|"vip"|"new"|"inactive" });
  const [sending, setSending] = useState(false);
  const [preview, setPreview] = useState(false);

  useEffect(() => {
    const load = async () => {
      const profile = await getCurrentUserProfile();
      if (!profile?.salon) { router.push("/login"); return; }
      setSalonId(profile.salon.id);
      setSalonName(profile.salon.name);
      setSalonSlug(profile.salon.slug || "");

      const [{ data: hist }, { data: appts }] = await Promise.all([
        supabase.from("broadcast_messages").select("*").eq("salon_id", profile.salon.id).order("created_at", { ascending: false }),
        supabase.from("appointments").select("client_name, client_email, client_phone, date_time, status").eq("salon_id", profile.salon.id),
      ]);
      setHistory(hist || []);

      // Build unique clients
      const map: Record<string, { name: string; phone: string; email: string; count: number; last: string }> = {};
      (appts || []).forEach((a: any) => {
        const key = a.client_email || a.client_name;
        if (!map[key]) map[key] = { name: a.client_name, phone: a.client_phone || "", email: a.client_email || "", count: 0, last: a.date_time };
        map[key].count++;
        if (a.date_time > map[key].last) map[key].last = a.date_time;
      });
      setClients(Object.values(map));
      setLoading(false);
    };
    load();
  }, [router]);

  const filteredClients = clients.filter(c => {
    if (form.filter === "all") return true;
    return true; // could add vip/new/inactive filters
  });

  const recipientCount = filteredClients.length;

  const applyTemplate = (t: typeof TEMPLATES[0]) => {
    const msg = t.message
      .replace(/{salon}/g, salonName)
      .replace(/{link}/g, `${typeof window !== "undefined" ? window.location.origin : ""}/book/${salonSlug}`);
    setForm(f => ({ ...f, message: msg, title: t.label.replace(/[^\w\s]/g, "").trim() }));
  };

  const handleSend = async () => {
    if (!salonId || !form.message || !form.title) { toast.error("Title and message required"); return; }
    if (!confirm(`Send to ${recipientCount} clients via ${form.channel.toUpperCase()}?`)) return;
    setSending(true);
    const { data, error } = await supabase.from("broadcast_messages").insert({
      salon_id: salonId, title: form.title, message: form.message,
      channel: form.channel, recipient_count: recipientCount, status: "sent",
    }).select().single();
    if (error) { toast.error("Failed to log broadcast"); setSending(false); return; }
    setHistory(p => [data, ...p]);
    toast.success(`Broadcast logged for ${recipientCount} clients!`);
    setForm({ title: "", message: "", channel: "whatsapp", filter: "all" });
    setSending(false);
  };

  const channelIcon = { whatsapp: "≡ƒô▒", sms: "≡ƒÆ¼", email: "≡ƒôº" };
  const channelColor = { whatsapp: "#25D366", sms: "#6366F1", email: "#F59E0B" };

  const Topbar = (
    <header style={{ background: "#fff", borderBottom: "1px solid #F1F5F9", padding: "0 24px", height: 66, display: "flex", alignItems: "center", justifyContent: "space-between", position: "sticky", top: 0, zIndex: 30, boxShadow: "0 1px 3px rgba(0,0,0,0.04)" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
        <HamburgerBtn onClick={() => {}} />
        <div>
          <div style={{ fontSize: 15, fontWeight: 800, color: "#0F172A" }}>≡ƒôó Broadcast Messages</div>
          <div style={{ fontSize: 11.5, color: "#94A3B8", marginTop: 1 }}>Send bulk messages to all clients</div>
        </div>
      </div>
    </header>
  );

  if (loading) return <DashboardShell salonName={salonName} topbar={Topbar}><div style={{ padding: 40, textAlign: "center", color: "#94A3B8" }}>LoadingΓÇª</div></DashboardShell>;

  return (
    <DashboardShell salonName={salonName} topbar={Topbar}>
      <div style={{ padding: "28px 24px", maxWidth: 1200, margin: "0 auto", display: "grid", gridTemplateColumns: "1fr 380px", gap: 24 }}>

        {/* Compose */}
        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          <div style={{ background: "#fff", border: "1.5px solid #F1F5F9", borderRadius: 20, padding: "22px 24px", boxShadow: "0 2px 8px rgba(0,0,0,0.03)" }}>
            <div style={{ fontSize: 15, fontWeight: 800, color: "#0F172A", marginBottom: 20 }}>Γ£ì∩╕Å Compose Message</div>

            {/* Channel selector */}
            <div style={{ marginBottom: 16 }}>
              <label style={{ fontSize: 12, fontWeight: 700, color: "#475569", display: "block", marginBottom: 8 }}>Channel</label>
              <div style={{ display: "flex", gap: 10 }}>
                {(["whatsapp", "sms", "email"] as const).map(ch => (
                  <button key={ch} onClick={() => setForm(f => ({ ...f, channel: ch }))}
                    style={{ flex: 1, padding: "10px 4px", borderRadius: 12, border: `2px solid ${form.channel === ch ? channelColor[ch] : "#E2E8F0"}`, background: form.channel === ch ? `${channelColor[ch]}12` : "#fff", cursor: "pointer", transition: "all 0.12s", display: "flex", flexDirection: "column", alignItems: "center", gap: 4 }}>
                    <span style={{ fontSize: 22 }}>{channelIcon[ch]}</span>
                    <span style={{ fontSize: 11.5, fontWeight: 800, color: form.channel === ch ? channelColor[ch] : "#64748B", textTransform: "capitalize" }}>{ch}</span>
                  </button>
                ))}
              </div>
            </div>

            {/* Audience */}
            <div style={{ marginBottom: 16, padding: "12px 16px", background: "#F8FAFC", borderRadius: 12, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <div>
                <div style={{ fontSize: 12.5, fontWeight: 700, color: "#0F172A" }}>Recipients</div>
                <div style={{ fontSize: 11.5, color: "#94A3B8" }}>All {recipientCount} clients</div>
              </div>
              <div style={{ fontSize: 22, fontWeight: 900, color: "#6366F1" }}>{recipientCount}</div>
            </div>

            {/* Title */}
            <div style={{ marginBottom: 14 }}>
              <label style={{ fontSize: 12, fontWeight: 700, color: "#475569", display: "block", marginBottom: 6 }}>Campaign Title *</label>
              <input value={form.title} onChange={e => setForm(f => ({ ...f, title: e.target.value }))} placeholder="e.g. Summer Discount Campaign"
                style={{ width: "100%", padding: "10px 13px", border: "1.5px solid #E2E8F0", borderRadius: 10, fontSize: 14, outline: "none", fontFamily: "inherit", boxSizing: "border-box" }} />
            </div>

            {/* Message */}
            <div style={{ marginBottom: 14 }}>
              <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 6 }}>
                <label style={{ fontSize: 12, fontWeight: 700, color: "#475569" }}>Message *</label>
                <span style={{ fontSize: 11, color: "#94A3B8" }}>{form.message.length} chars</span>
              </div>
              <textarea value={form.message} onChange={e => setForm(f => ({ ...f, message: e.target.value }))} placeholder="Type your messageΓÇª Use {name} for client name, {salon} for salon name" rows={5}
                style={{ width: "100%", padding: "10px 13px", border: "1.5px solid #E2E8F0", borderRadius: 10, fontSize: 13.5, fontFamily: "inherit", outline: "none", resize: "vertical", boxSizing: "border-box", lineHeight: 1.6 }} />
              <div style={{ fontSize: 11, color: "#94A3B8", marginTop: 4 }}>Variables: {"{"}<b>name</b>{"}"}, {"{"}<b>salon</b>{"}"}, {"{"}<b>link</b>{"}"}</div>
            </div>

            {/* Preview */}
            {form.message && (
              <div style={{ marginBottom: 16, padding: "14px 16px", background: "#F8FAFC", borderRadius: 12, border: "1.5px solid #E2E8F0" }}>
                <div style={{ fontSize: 11, fontWeight: 700, color: "#94A3B8", marginBottom: 6, textTransform: "uppercase", letterSpacing: "0.5px" }}>Preview (for "Sarah")</div>
                <div style={{ fontSize: 13.5, color: "#334155", lineHeight: 1.7 }}>
                  {form.message.replace(/{name}/g, "Sarah").replace(/{salon}/g, salonName).replace(/{link}/g, "featuresalon.com/book")}
                </div>
              </div>
            )}

            <button onClick={handleSend} disabled={sending || !form.message || !form.title}
              style={{ width: "100%", padding: "13px", background: `linear-gradient(135deg,${channelColor[form.channel]},${channelColor[form.channel]}cc)`, border: "none", borderRadius: 12, fontSize: 14, fontWeight: 800, color: "#fff", cursor: "pointer", opacity: !form.message || !form.title ? 0.5 : 1, boxShadow: `0 4px 14px ${channelColor[form.channel]}40`, transition: "all 0.15s" }}>
              {sending ? "SendingΓÇª" : `${channelIcon[form.channel]} Send to ${recipientCount} clients`}
            </button>
          </div>
        </div>

        {/* Right column */}
        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          {/* Templates */}
          <div style={{ background: "#fff", border: "1.5px solid #F1F5F9", borderRadius: 20, padding: "20px 20px", boxShadow: "0 2px 8px rgba(0,0,0,0.03)" }}>
            <div style={{ fontSize: 14, fontWeight: 800, color: "#0F172A", marginBottom: 14 }}>ΓÜí Quick Templates</div>
            <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
              {TEMPLATES.map((t, i) => (
                <button key={i} onClick={() => applyTemplate(t)}
                  style={{ padding: "10px 14px", background: "#F8FAFC", border: "1.5px solid #E2E8F0", borderRadius: 12, textAlign: "left", fontSize: 13, fontWeight: 600, color: "#334155", cursor: "pointer", transition: "all 0.12s" }}
                  onMouseEnter={e => { e.currentTarget.style.background = "#EEF2FF"; e.currentTarget.style.borderColor = "#C7D2FE"; }}
                  onMouseLeave={e => { e.currentTarget.style.background = "#F8FAFC"; e.currentTarget.style.borderColor = "#E2E8F0"; }}>
                  {t.label}
                </button>
              ))}
            </div>
          </div>

          {/* History */}
          <div style={{ background: "#fff", border: "1.5px solid #F1F5F9", borderRadius: 20, overflow: "hidden", boxShadow: "0 2px 8px rgba(0,0,0,0.03)" }}>
            <div style={{ padding: "16px 20px", borderBottom: "1px solid #F1F5F9", fontSize: 14, fontWeight: 800, color: "#0F172A" }}>≡ƒôï Sent History</div>
            <div style={{ maxHeight: 320, overflowY: "auto" }}>
              {history.length === 0 ? (
                <div style={{ textAlign: "center", padding: "30px 0", color: "#94A3B8", fontSize: 13 }}>No broadcasts sent yet</div>
              ) : history.map(h => (
                <div key={h.id} style={{ padding: "14px 18px", borderBottom: "1px solid #F8FAFC" }}>
                  <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
                    <div style={{ fontSize: 13, fontWeight: 700, color: "#0F172A" }}>{h.title}</div>
                    <span style={{ fontSize: 11, fontWeight: 700, padding: "2px 8px", borderRadius: 99, background: `${channelColor[h.channel as keyof typeof channelColor]}18`, color: channelColor[h.channel as keyof typeof channelColor] }}>
                      {channelIcon[h.channel as keyof typeof channelIcon]} {h.channel}
                    </span>
                  </div>
                  <div style={{ fontSize: 11.5, color: "#64748B", marginBottom: 4 }}>{h.recipient_count} recipients</div>
                  <div style={{ fontSize: 11, color: "#94A3B8" }}>{new Date(h.created_at).toLocaleDateString("en-GB", { day:"numeric", month:"short", year:"numeric", hour:"2-digit", minute:"2-digit" })}</div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </DashboardShell>
  );
}

export default function BroadcastPage() {
  return (
    <FeatureGate feature="analytics_basic">
      <BroadcastContent />
    </FeatureGate>
  );
}

