                ...filtered.map(c => [c.name, c.email, c.phone, c.count, `┬ú${c.revenue}`, new Date(c.last_visit).toLocaleDateString("en-GB")])
              ].map(r => r.join(",")).join("\n");
              const blob = new Blob([csv], { type: "text/csv" });
              const a = document.createElement("a"); a.href = URL.createObjectURL(blob); a.download = "clients.csv"; a.click();
              toast.success("Clients exported!");
            }} style={{ padding: "7px 14px", background: "#F8FAFC", border: "1.5px solid #E2E8F0", borderRadius: 10, fontSize: 12.5, fontWeight: 700, cursor: "pointer", color: "#475569" }}>≡ƒôÑ Export</button>
          </div>
          {filtered.length === 0 ? (
