                { label: "Client Type", value: selected.count >= 5 || selected.revenue >= 200 ? "Γ¡É VIP" : selected.count === 1 ? "≡ƒåò New" : "≡ƒöä Regular", color: "#EC4899" },
              ].map(s => (
