                        <td style={{ padding:"12px 16px", borderBottom:"1px solid var(--border)" }}>
                          <span style={{ fontSize:11, color:"var(--indigo)", fontWeight:600 }}>View ΓåÆ</span>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
