        {selected && (
          <div style={{ flex:"0 0 46%", minWidth:0, background:"var(--surface)", border:"1px solid var(--border)", borderRadius:"var(--r-lg)", overflow:"hidden", boxShadow:"var(--shadow-md)", display:"flex", flexDirection:"column", maxHeight:"80vh" }}>

