                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

"use client";
import React, { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { supabase } from "../../lib/supabase";
import { getCurrentUserProfile } from "@/app/lib/auth";
import DashboardShell, { HamburgerBtn } from "../components/DashboardShell";
import { useToast } from "../components/Toast";

interface ClosedDate {
  id: string;
  date: string;
  reason: string;
}

const MONTHS = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
const DAYS = ["Mon","Tue","Wed","Thu","Fri","Sat","Sun"];

function getMonday(date: Date) {
  const d = new Date(date);
  const day = d.getDay();
  d.setDate(d.getDate() - (day === 0 ? 6 : day - 1));
  d.setHours(0,0,0,0);
  return d;
}

export default function ClosedDatesPage() {
  const router = useRouter();
  const toast = useToast();
  const [salonId, setSalonId] = useState<string|null>(null);
  const [salonName, setSalonName] = useState("");
  const [closedDates, setClosedDates] = useState<ClosedDate[]>([]);
  const [loading, setLoading] = useState(true);
  const [weekStart, setWeekStart] = useState(getMonday(new Date()));
  const [showModal, setShowModal] = useState(false);
  const [form, setForm] = useState({ date: "", reason: "" });
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    const load = async () => {
      const profile = await getCurrentUserProfile();
      if (!profile?.salon) { router.push("/login"); return; }
      setSalonId(profile.salon.id);
      setSalonName(profile.salon.name);
      const { data } = await supabase.from("closed_dates").select("*").eq("salon_id", profile.salon.id).order("date");
      setClosedDates(data || []);
      setLoading(false);
    };
    load();
  }, [router]);

  const weekDays = Array.from({length:7},(_,i) => {
    const d = new Date(weekStart);
    d.setDate(d.getDate() + i);
    return d;
  });

  const isClosed = (date: Date) => {
    const ds = date.toISOString().slice(0,10);
    return closedDates.find(c => c.date === ds);
  };

  const handleAdd = async () => {
    if (!salonId || !form.date) { toast.error("Date required"); return; }
    setSaving(true);
    const { data, error } = await supabase.from("closed_dates").insert({
      salon_id: salonId, date: form.date, reason: form.reason
    }).select().single();
    if (error) { toast.error("Date already closed or error"); setSaving(false); return; }
    setClosedDates(p => [...p, data].sort((a,b) => a.date.localeCompare(b.date)));
    toast.success("Closed date added!");
    setShowModal(false);
    setForm({ date: "", reason: "" });
    setSaving(false);
  };

  const handleRemove = async (id: string, date: string) => {
    await supabase.from("closed_dates").delete().eq("id", id);
    setClosedDates(p => p.filter(c => c.id !== id));
    toast.success(`${date} removed`);
  };

  const quickAdd = async (date: Date, reason: string) => {
    if (!salonId) return;
    const ds = date.toISOString().slice(0,10);
    const existing = closedDates.find(c => c.date === ds);
    if (existing) { handleRemove(existing.id, ds); return; }
    const { data, error } = await supabase.from("closed_dates").insert({ salon_id: salonId, date: ds, reason }).select().single();
    if (!error && data) {
      setClosedDates(p => [...p, data].sort((a,b) => a.date.localeCompare(b.date)));
      toast.success(`${ds} marked as closed`);
    }
  };

  const Topbar = (
    <header style={{ background:"#fff", borderBottom:"1px solid #F1F5F9", padding:"0 24px", height:66, display:"flex", alignItems:"center", justifyContent:"space-between", position:"sticky", top:0, zIndex:30, boxShadow:"0 1px 3px rgba(0,0,0,0.04)" }}>
      <div style={{ display:"flex", alignItems:"center", gap:14 }}>
        <HamburgerBtn onClick={() => {}} />
        <div>
          <div style={{ fontSize:15, fontWeight:800, color:"#0F172A" }}>≡ƒÜ½ Closed Dates</div>
          <div style={{ fontSize:11.5, color:"#94A3B8", marginTop:1 }}>Manage holidays & salon closures</div>
        </div>
      </div>
      <button onClick={() => setShowModal(true)} style={{ padding:"9px 18px", background:"linear-gradient(135deg,#EF4444,#DC2626)", color:"#fff", border:"none", borderRadius:12, fontSize:13, fontWeight:700, cursor:"pointer", boxShadow:"0 4px 14px rgba(239,68,68,0.3)" }}>+ Add Closure</button>
    </header>
  );

  if (loading) return <DashboardShell salonName={salonName} topbar={Topbar}><div style={{ padding:40, textAlign:"center", color:"#94A3B8" }}>LoadingΓÇª</div></DashboardShell>;

  const now = new Date();
  const upcoming = closedDates.filter(c => c.date >= now.toISOString().slice(0,10));
  const past = closedDates.filter(c => c.date < now.toISOString().slice(0,10));

  return (
    <DashboardShell salonName={salonName} topbar={Topbar}>
      <div style={{ padding:"28px 24px", maxWidth:1200, margin:"0 auto" }}>

        {/* Stats */}
        <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:14, marginBottom:24 }}>
          {[
            { label:"Total Closures", value:closedDates.length, icon:"≡ƒÜ½", color:"#EF4444" },
            { label:"Upcoming", value:upcoming.length, icon:"≡ƒôà", color:"#F59E0B" },
            { label:"Past Closures", value:past.length, icon:"Γ£à", color:"#10B981" },
          ].map(s => (
            <div key={s.label} style={{ background:"#fff", border:"1.5px solid #F1F5F9", borderRadius:16, padding:"18px 20px", position:"relative", overflow:"hidden" }}>
              <div style={{ position:"absolute", top:0, left:0, right:0, height:3, background:s.color }} />
              <div style={{ display:"flex", justifyContent:"space-between", marginBottom:8 }}>
                <span style={{ fontSize:10, fontWeight:800, color:"#94A3B8", textTransform:"uppercase", letterSpacing:"0.8px" }}>{s.label}</span>
                <span style={{ fontSize:20 }}>{s.icon}</span>
              </div>
              <div style={{ fontSize:28, fontWeight:900, color:"#0F172A" }}>{s.value}</div>
            </div>
          ))}
        </div>

        <div style={{ display:"grid", gridTemplateColumns:"1fr 360px", gap:20 }}>
          {/* Calendar */}
          <div style={{ background:"#fff", border:"1.5px solid #F1F5F9", borderRadius:20, overflow:"hidden", boxShadow:"0 2px 8px rgba(0,0,0,0.03)" }}>
            <div style={{ padding:"16px 20px", borderBottom:"1px solid #F1F5F9", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
              <div style={{ fontSize:15, fontWeight:800, color:"#0F172A" }}>
                {weekDays[0].toLocaleDateString("en-GB", { day:"numeric", month:"short" })} ΓÇô {weekDays[6].toLocaleDateString("en-GB", { day:"numeric", month:"short", year:"numeric" })}
              </div>
              <div style={{ display:"flex", gap:6 }}>
                {(["ΓåÉ Prev","Today","Next ΓåÆ"] as const).map((lbl,i) => (
                  <button key={lbl} onClick={() => {
                    if (i === 1) setWeekStart(getMonday(new Date()));
                    else { const d = new Date(weekStart); d.setDate(d.getDate() + (i===0?-7:7)); setWeekStart(d); }
                  }} style={{ padding:"6px 12px", background: i===1 ? "#6366F1" : "#F8FAFC", color: i===1 ? "#fff" : "#475569", border:`1.5px solid ${i===1 ? "transparent" : "#E2E8F0"}`, borderRadius:8, fontSize:12, fontWeight:700, cursor:"pointer" }}>{lbl}</button>
                ))}
              </div>
            </div>
            <div style={{ display:"grid", gridTemplateColumns:"repeat(7,1fr)", gap:0 }}>
              {DAYS.map(d => (
                <div key={d} style={{ textAlign:"center", padding:"10px 4px", fontSize:10, fontWeight:800, color:"#94A3B8", textTransform:"uppercase", letterSpacing:"0.5px", borderBottom:"1px solid #F1F5F9", background:"#FAFAFA" }}>{d}</div>
              ))}
              {weekDays.map(day => {
                const closed = isClosed(day);
                const isToday = day.toDateString() === now.toDateString();
                const isPast = day < now && !isToday;
                return (
                  <div key={day.toISOString()}
                    onClick={() => !isPast && quickAdd(day, "Holiday")}
                    style={{ minHeight:80, padding:"10px 8px", borderRight:"1px solid #F8FAFC", borderBottom:"1px solid #F8FAFC", background: closed ? "#FEF2F2" : isToday ? "#EEF2FF" : "#fff", cursor: isPast ? "default" : "pointer", transition:"all 0.15s", position:"relative" }}
                    onMouseEnter={e => { if (!isPast) e.currentTarget.style.background = closed ? "#FEE2E2" : "#F8FAFC"; }}
                    onMouseLeave={e => { e.currentTarget.style.background = closed ? "#FEF2F2" : isToday ? "#EEF2FF" : "#fff"; }}
                  >
                    <div style={{ fontSize:13, fontWeight: isToday ? 900 : 600, color: closed ? "#DC2626" : isToday ? "#4F46E5" : isPast ? "#CBD5E1" : "#0F172A", marginBottom:4 }}>{day.getDate()}</div>
                    {closed && (
                      <div style={{ fontSize:9.5, fontWeight:700, color:"#DC2626", background:"#FEE2E2", padding:"2px 6px", borderRadius:5, lineHeight:1.4 }}>
                        ≡ƒÜ½ {closed.reason || "Closed"}
                      </div>
                    )}
                    {!closed && !isPast && (
                      <div style={{ fontSize:9, color:"#CBD5E1", marginTop:4 }}>Click to close</div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>

          {/* List */}
          <div style={{ display:"flex", flexDirection:"column", gap:14 }}>
            {/* Upcoming closures */}
            <div style={{ background:"#fff", border:"1.5px solid #F1F5F9", borderRadius:20, overflow:"hidden", boxShadow:"0 2px 8px rgba(0,0,0,0.03)" }}>
              <div style={{ padding:"16px 20px", borderBottom:"1px solid #F1F5F9" }}>
                <div style={{ fontSize:14, fontWeight:800, color:"#0F172A" }}>≡ƒôà Upcoming Closures</div>
              </div>
              <div style={{ padding:12, display:"flex", flexDirection:"column", gap:8, maxHeight:280, overflowY:"auto" }}>
                {upcoming.length === 0 && <div style={{ textAlign:"center", padding:"20px 0", color:"#94A3B8", fontSize:13 }}>No upcoming closures</div>}
                {upcoming.map(c => (
                  <div key={c.id} style={{ display:"flex", justifyContent:"space-between", alignItems:"center", padding:"10px 14px", background:"#FEF2F2", border:"1.5px solid #FECACA", borderRadius:12 }}>
                    <div>
                      <div style={{ fontSize:13, fontWeight:800, color:"#DC2626" }}>{new Date(c.date + "T00:00:00").toLocaleDateString("en-GB", { weekday:"short", day:"numeric", month:"short", year:"numeric" })}</div>
                      <div style={{ fontSize:11.5, color:"#EF4444", marginTop:2 }}>{c.reason || "No reason given"}</div>
                    </div>
                    <button onClick={() => handleRemove(c.id, c.date)} style={{ background:"none", border:"none", cursor:"pointer", fontSize:16, color:"#FCA5A5" }}
                      onMouseEnter={e => { e.currentTarget.style.color = "#EF4444"; }} onMouseLeave={e => { e.currentTarget.style.color = "#FCA5A5"; }}>≡ƒùæ</button>
                  </div>
                ))}
              </div>
            </div>

            {/* Quick add common */}
            <div style={{ background:"#fff", border:"1.5px solid #F1F5F9", borderRadius:20, padding:"16px 20px" }}>
              <div style={{ fontSize:13, fontWeight:800, color:"#0F172A", marginBottom:12 }}>ΓÜí Quick Add UK Holidays</div>
              {[
                { label:"Christmas Day", date:"2025-12-25" },
                { label:"Boxing Day", date:"2025-12-26" },
                { label:"New Year's Day", date:"2026-01-01" },
                { label:"Easter Monday", date:"2026-04-06" },
                { label:"Early May Bank", date:"2026-05-04" },
              ].map(h => {
                const isCl = closedDates.find(c => c.date === h.date);
                return (
                  <button key={h.date} onClick={async () => {
                    if (!salonId) return;
                    if (isCl) { handleRemove(isCl.id, h.date); return; }
                    const { data } = await supabase.from("closed_dates").insert({ salon_id: salonId, date: h.date, reason: h.label }).select().single();
                    if (data) { setClosedDates(p => [...p, data].sort((a,b) => a.date.localeCompare(b.date))); toast.success(`${h.label} added!`); }
                  }}
                  style={{ width:"100%", textAlign:"left", padding:"8px 12px", marginBottom:6, borderRadius:10, border:`1.5px solid ${isCl ? "#FECACA" : "#E2E8F0"}`, background: isCl ? "#FEF2F2" : "#F8FAFC", fontSize:12.5, fontWeight:600, color: isCl ? "#DC2626" : "#475569", cursor:"pointer", display:"flex", justifyContent:"space-between", transition:"all 0.12s" }}>
                    <span>{h.label}</span>
                    <span style={{ fontSize:11, color:"#94A3B8" }}>{isCl ? "Γ£ô Added" : h.date}</span>
                  </button>
                );
              })}
            </div>
          </div>
        </div>
      </div>

      {/* Modal */}
      {showModal && (
        <div onClick={() => setShowModal(false)} style={{ position:"fixed", inset:0, background:"rgba(15,23,42,0.55)", zIndex:9999, display:"flex", alignItems:"center", justifyContent:"center", padding:16, backdropFilter:"blur(4px)" }}>
          <div onClick={e => e.stopPropagation()} style={{ background:"#fff", borderRadius:20, padding:28, width:"100%", maxWidth:400, boxShadow:"0 32px 80px rgba(0,0,0,0.2)" }}>
            <div style={{ fontSize:18, fontWeight:900, color:"#0F172A", marginBottom:20 }}>≡ƒÜ½ Add Closure</div>
            <div style={{ display:"flex", flexDirection:"column", gap:14 }}>
              <div>
                <label style={{ fontSize:12, fontWeight:700, color:"#475569", display:"block", marginBottom:6 }}>Date *</label>
                <input type="date" value={form.date} onChange={e => setForm({...form, date:e.target.value})} style={{ width:"100%", padding:"10px 13px", border:"1.5px solid #E2E8F0", borderRadius:10, fontSize:14, outline:"none", fontFamily:"inherit", boxSizing:"border-box" }} />
              </div>
              <div>
                <label style={{ fontSize:12, fontWeight:700, color:"#475569", display:"block", marginBottom:6 }}>Reason (optional)</label>
                <input value={form.reason} onChange={e => setForm({...form, reason:e.target.value})} placeholder="e.g. Christmas, Holiday, Staff Training" style={{ width:"100%", padding:"10px 13px", border:"1.5px solid #E2E8F0", borderRadius:10, fontSize:14, outline:"none", fontFamily:"inherit", boxSizing:"border-box" }} />
              </div>
            </div>
            <div style={{ display:"flex", gap:10, marginTop:20 }}>
              <button onClick={() => setShowModal(false)} style={{ flex:1, padding:12, background:"#F8FAFC", border:"1.5px solid #E2E8F0", borderRadius:12, fontSize:13.5, fontWeight:700, color:"#475569", cursor:"pointer" }}>Cancel</button>
              <button onClick={handleAdd} disabled={saving || !form.date} style={{ flex:2, padding:12, background:"linear-gradient(135deg,#EF4444,#DC2626)", border:"none", borderRadius:12, fontSize:13.5, fontWeight:700, color:"#fff", cursor:"pointer", opacity: !form.date ? 0.5 : 1 }}>
                {saving ? "SavingΓÇª" : "Add Closure"}
              </button>
            </div>
          </div>
        </div>
      )}
    </DashboardShell>
  );
}

"use client";
import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { supabase } from "../../lib/supabase";
import {
  hasFeatureAccess,
  PLAN_LABELS,
  PLAN_RANK,
  FEATURE_META,
  type Feature,
  type Plan,
} from "../../lib/featureAccess";

interface FeatureGateProps {
  feature: Feature;
  children: React.ReactNode;
}

export default function FeatureGate({ feature, children }: FeatureGateProps) {
  const router = useRouter();
  const [status, setStatus] = useState<"loading" | "allowed" | "locked">("loading");
  const [plan, setPlan] = useState<string | null>(null);
  const [subStatus, setSubStatus] = useState<string | null>(null);
  const [hasCustId, setHasCustId] = useState(false);
  const [salonId, setSalonId] = useState<string | null>(null);

  useEffect(() => {
    const check = async () => {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) { router.push("/login"); return; }

      const { data: salon } = await supabase
        .from("salons")
        .select("id, subscription_status, subscription_plan, stripe_customer_id")
        .eq("owner_id", user.id)
        .single();

      if (!salon) { router.push("/login"); return; }

      setSalonId(salon.id);
      setPlan(salon.subscription_plan);
      setSubStatus(salon.subscription_status);
      setHasCustId(!!salon.stripe_customer_id);

      const allowed = hasFeatureAccess(feature, salon.subscription_plan, salon.subscription_status);
      setStatus(allowed ? "allowed" : "locked");
    };
    check();
  }, [feature, router]);

  if (status === "loading") {
    return (
      <div style={{ display: "flex", alignItems: "center", justifyContent: "center", height: "60vh" }}>
        <div style={{ textAlign: "center", color: "#94A3B8" }}>
          <div style={{ fontSize: 32, marginBottom: 12, animation: "spin 1s linear infinite" }}>ΓÅ│</div>
          <div style={{ fontSize: 14, fontWeight: 600 }}>Checking accessΓÇª</div>
        </div>
      </div>
    );
  }

  if (status === "allowed") return <>{children}</>;

  // ΓöÇΓöÇ LOCKED SCREEN ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  const meta = FEATURE_META[feature];
  const requiredPlan = meta.requiredPlan;
  const requiredInfo = PLAN_LABELS[requiredPlan];
  const currentPlan = (plan || "starter").toLowerCase() as Plan;
  const currentInfo = PLAN_LABELS[currentPlan] || PLAN_LABELS.starter;

  const openPortal = async () => {
    if (!hasCustId) { router.push("/subscribe"); return; }
    const res = await fetch("/api/subscription/portal", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ salonId }),
    });
    const data = await res.json();
    if (data.url) window.location.href = data.url;
  };

  // Plans in upgrade order above current
  const allPlans: Plan[] = ["pro", "business", "enterprise"];
  const upgradePlans = allPlans.filter(p => PLAN_RANK[p] >= PLAN_RANK[requiredPlan]);

  return (
    <div style={{ display: "flex", alignItems: "center", justifyContent: "center", minHeight: "70vh", padding: "40px 24px" }}>
      <div style={{ maxWidth: 520, width: "100%", textAlign: "center" }}>

        {/* Lock icon with glow */}
        <div style={{ position: "relative", display: "inline-block", marginBottom: 28 }}>
          <div style={{ width: 90, height: 90, borderRadius: 26, background: "linear-gradient(135deg,#1E1B4B,#3730A3)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 40, margin: "0 auto", boxShadow: "0 16px 48px rgba(99,102,241,0.35)" }}>
            ≡ƒöÆ
          </div>
          <div style={{ position: "absolute", bottom: -4, right: -4, background: "#F59E0B", borderRadius: "50%", width: 28, height: 28, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 14, border: "2px solid #fff" }}>
            {meta.icon}
          </div>
        </div>

        <h1 style={{ fontSize: 26, fontWeight: 900, color: "#0F172A", letterSpacing: "-0.8px", margin: "0 0 10px" }}>
          {meta.label} is Locked
        </h1>
        <p style={{ fontSize: 14.5, color: "#64748B", lineHeight: 1.7, margin: "0 0 28px" }}>
          You&apos;re currently on the{" "}
          <span style={{ fontWeight: 800, color: currentInfo.color }}>{currentInfo.name}</span> plan.
          Upgrade to <span style={{ fontWeight: 800, color: requiredInfo.color }}>{requiredInfo.name}</span> or higher to unlock {meta.icon} {meta.label}.
        </p>

        {/* Plan cards */}
        <div style={{ display: "grid", gridTemplateColumns: `repeat(${upgradePlans.length}, 1fr)`, gap: 12, marginBottom: 24 }}>
          {upgradePlans.map(p => {
            const info = PLAN_LABELS[p];
            const isRecommended = p === requiredPlan;
            return (
              <div key={p}
                style={{ border: `2px solid ${isRecommended ? info.color : "#E2E8F0"}`, borderRadius: 16, padding: "16px 14px", background: isRecommended ? `${info.color}08` : "#fff", position: "relative", transition: "all 0.15s" }}>
                {isRecommended && (
                  <div style={{ position: "absolute", top: -10, left: "50%", transform: "translateX(-50%)", background: info.color, color: "#fff", fontSize: 9.5, fontWeight: 900, padding: "2px 10px", borderRadius: 99, letterSpacing: "0.5px", whiteSpace: "nowrap" }}>
                    RECOMMENDED
                  </div>
                )}
                <div style={{ fontSize: 13.5, fontWeight: 800, color: "#0F172A", marginBottom: 2, textTransform: "capitalize" }}>{info.name}</div>
                <div style={{ fontSize: 20, fontWeight: 900, color: info.color, letterSpacing: "-0.5px" }}>{info.price}</div>
              </div>
            );
          })}
        </div>

        {/* CTA */}
        <button
          onClick={openPortal}
          style={{ width: "100%", padding: "15px", background: `linear-gradient(135deg,${requiredInfo.color},${requiredInfo.color}cc)`, color: "#fff", border: "none", borderRadius: 14, fontSize: 15, fontWeight: 800, cursor: "pointer", boxShadow: `0 8px 24px ${requiredInfo.color}40`, letterSpacing: "-0.3px", transition: "all 0.18s", marginBottom: 10 }}
          onMouseEnter={e => { e.currentTarget.style.transform = "translateY(-2px)"; e.currentTarget.style.boxShadow = `0 16px 40px ${requiredInfo.color}50`; }}
          onMouseLeave={e => { e.currentTarget.style.transform = "none"; e.currentTarget.style.boxShadow = `0 8px 24px ${requiredInfo.color}40`; }}
        >
          {hasCustId ? "Upgrade Plan ΓåÆ" : "Choose a Plan ΓåÆ"}
        </button>

        <button
          onClick={() => router.push("/dashboard")}
          style={{ background: "none", border: "none", cursor: "pointer", fontSize: 13, color: "#94A3B8", fontWeight: 600, padding: 0 }}
          onMouseEnter={e => { e.currentTarget.style.color = "#475569"; }}
          onMouseLeave={e => { e.currentTarget.style.color = "#94A3B8"; }}
        >
          ΓåÉ Back to Dashboard
        </button>
      </div>
    </div>
  );
}

"use client";
import React, { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { supabase } from "../../lib/supabase";
import { getCurrentUserProfile } from "@/app/lib/auth";
import DashboardShell, { HamburgerBtn } from "../components/DashboardShell";
import { useToast } from "../components/Toast";

interface Photo { id: string; url: string; caption: string; category: string; is_featured: boolean; created_at: string; }

const CATEGORIES = ["general", "haircut", "color", "styling", "nails", "beard", "facial", "before-after"];

export default function GalleryPage() {
  const router = useRouter();
  const toast = useToast();
  const [salonId, setSalonId] = useState<string | null>(null);
  const [salonName, setSalonName] = useState("");
  const [photos, setPhotos] = useState<Photo[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [lightbox, setLightbox] = useState<Photo | null>(null);
  const [filter, setFilter] = useState("all");
  const [form, setForm] = useState({ url: "", caption: "", category: "general", is_featured: false });

  useEffect(() => {
    const load = async () => {
      const profile = await getCurrentUserProfile();
      if (!profile?.salon) { router.push("/login"); return; }
      setSalonId(profile.salon.id);
      setSalonName(profile.salon.name);
      const { data } = await supabase.from("gallery_photos").select("*").eq("salon_id", profile.salon.id).order("created_at", { ascending: false });
      setPhotos(data || []);
      setLoading(false);
    };
    load();
  }, [router]);

  const handleAdd = async () => {
    if (!salonId || !form.url) { toast.error("Image URL required"); return; }
    const { data, error } = await supabase.from("gallery_photos").insert({ salon_id: salonId, ...form }).select().single();
    if (error) { toast.error("Failed to add photo"); return; }
    setPhotos(p => [data, ...p]);
    toast.success("Photo added!");
    setShowModal(false);
    setForm({ url: "", caption: "", category: "general", is_featured: false });
  };

  const toggleFeatured = async (id: string, current: boolean) => {
    await supabase.from("gallery_photos").update({ is_featured: !current }).eq("id", id);
    setPhotos(p => p.map(ph => ph.id === id ? { ...ph, is_featured: !current } : ph));
    toast.success(current ? "Unfeatured" : "Featured!");
  };

  const deletePhoto = async (id: string) => {
    if (!confirm("Delete this photo?")) return;
    await supabase.from("gallery_photos").delete().eq("id", id);
    setPhotos(p => p.filter(ph => ph.id !== id));
    toast.success("Photo deleted");
  };

  const filtered = filter === "all" ? photos : filter === "featured" ? photos.filter(p => p.is_featured) : photos.filter(p => p.category === filter);

  const Topbar = (
    <header style={{ background: "#fff", borderBottom: "1px solid #F1F5F9", padding: "0 24px", height: 66, display: "flex", alignItems: "center", justifyContent: "space-between", position: "sticky", top: 0, zIndex: 30, boxShadow: "0 1px 3px rgba(0,0,0,0.04)" }}>
      <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
        <HamburgerBtn onClick={() => {}} />
        <div>
          <div style={{ fontSize: 15, fontWeight: 800, color: "#0F172A" }}>≡ƒô╕ Gallery</div>
          <div style={{ fontSize: 11.5, color: "#94A3B8", marginTop: 1 }}>Showcase your salon work</div>
        </div>
      </div>
      <button onClick={() => setShowModal(true)} style={{ padding: "9px 18px", background: "linear-gradient(135deg,#EC4899,#DB2777)", color: "#fff", border: "none", borderRadius: 12, fontSize: 13, fontWeight: 700, cursor: "pointer", boxShadow: "0 4px 14px rgba(236,72,153,0.3)" }}>+ Add Photo</button>
    </header>
  );

  if (loading) return <DashboardShell salonName={salonName} topbar={Topbar}><div style={{ padding: 40, textAlign: "center", color: "#94A3B8" }}>LoadingΓÇª</div></DashboardShell>;

  return (
    <DashboardShell salonName={salonName} topbar={Topbar}>
      <div style={{ padding: "28px 24px", maxWidth: 1360, margin: "0 auto" }}>

        {/* Stats row */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 14, marginBottom: 24 }}>
          {[
            { label: "Total Photos", value: photos.length, color: "#EC4899" },
            { label: "Featured", value: photos.filter(p => p.is_featured).length, color: "#F59E0B" },
            { label: "Categories", value: new Set(photos.map(p => p.category)).size, color: "#6366F1" },
            { label: "This Month", value: photos.filter(p => new Date(p.created_at).getMonth() === new Date().getMonth()).length, color: "#10B981" },
          ].map(s => (
            <div key={s.label} style={{ background: "#fff", border: "1.5px solid #F1F5F9", borderRadius: 16, padding: "18px 16px", position: "relative", overflow: "hidden" }}>
              <div style={{ position: "absolute", top: 0, left: 0, right: 0, height: 3, background: s.color }} />
              <div style={{ fontSize: 10, fontWeight: 800, color: "#94A3B8", textTransform: "uppercase", letterSpacing: "0.8px", marginBottom: 8 }}>{s.label}</div>
              <div style={{ fontSize: 28, fontWeight: 900, color: "#0F172A" }}>{s.value}</div>
            </div>
          ))}
        </div>

        {/* Filter tabs */}
        <div style={{ display: "flex", gap: 8, flexWrap: "wrap", marginBottom: 20 }}>
          {["all", "featured", ...CATEGORIES].map(cat => (
            <button key={cat} onClick={() => setFilter(cat)}
              style={{ padding: "6px 14px", borderRadius: 20, border: `1.5px solid ${filter === cat ? "#EC4899" : "#E2E8F0"}`, background: filter === cat ? "#FDF2F8" : "#fff", color: filter === cat ? "#DB2777" : "#64748B", fontSize: 12.5, fontWeight: filter === cat ? 800 : 500, cursor: "pointer", transition: "all 0.12s", textTransform: "capitalize" }}>
              {cat} {cat === "all" ? `(${photos.length})` : cat === "featured" ? `(${photos.filter(p => p.is_featured).length})` : `(${photos.filter(p => p.category === cat).length})`}
            </button>
          ))}
        </div>

        {/* Grid */}
        {filtered.length === 0 ? (
          <div style={{ textAlign: "center", padding: "60px 0", color: "#94A3B8" }}>
            <div style={{ fontSize: 48, marginBottom: 12 }}>≡ƒô╕</div>
            <div style={{ fontWeight: 700 }}>No photos yet</div>
            <div style={{ fontSize: 13, marginTop: 4 }}>Add your salon portfolio photos</div>
          </div>
        ) : (
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(220px,1fr))", gap: 16 }}>
            {filtered.map(photo => (
              <div key={photo.id} style={{ position: "relative", borderRadius: 16, overflow: "hidden", boxShadow: "0 4px 16px rgba(0,0,0,0.08)", cursor: "pointer", transition: "transform 0.18s" }}
                onMouseEnter={e => { e.currentTarget.style.transform = "scale(1.02)"; }}
                onMouseLeave={e => { e.currentTarget.style.transform = "none"; }}>
                <img src={photo.url} alt={photo.caption} onClick={() => setLightbox(photo)}
                  style={{ width: "100%", height: 200, objectFit: "cover", display: "block" }}
                  onError={e => { (e.target as HTMLImageElement).src = `https://ui-avatars.com/api/?name=${encodeURIComponent(photo.caption||"Photo")}&size=400&background=F1F5F9&color=94A3B8`; }} />
                {photo.is_featured && (
                  <div style={{ position: "absolute", top: 10, left: 10, background: "#F59E0B", color: "#fff", fontSize: 10, fontWeight: 800, padding: "3px 8px", borderRadius: 99 }}>Γ¡É Featured</div>
                )}
                <div style={{ position: "absolute", top: 10, right: 10, display: "flex", gap: 6 }}>
                  <button onClick={e => { e.stopPropagation(); toggleFeatured(photo.id, photo.is_featured); }}
                    style={{ width: 28, height: 28, borderRadius: "50%", background: "rgba(255,255,255,0.9)", border: "none", cursor: "pointer", fontSize: 13, display: "flex", alignItems: "center", justifyContent: "center" }}>Γ¡É</button>
                  <button onClick={e => { e.stopPropagation(); deletePhoto(photo.id); }}
                    style={{ width: 28, height: 28, borderRadius: "50%", background: "rgba(255,255,255,0.9)", border: "none", cursor: "pointer", fontSize: 13, display: "flex", alignItems: "center", justifyContent: "center" }}>≡ƒùæ</button>
                </div>
                {photo.caption && (
                  <div style={{ position: "absolute", bottom: 0, left: 0, right: 0, background: "linear-gradient(transparent,rgba(0,0,0,0.7))", padding: "20px 12px 10px", color: "#fff", fontSize: 12, fontWeight: 600 }}>{photo.caption}</div>
                )}
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Lightbox */}
      {lightbox && (
        <div onClick={() => setLightbox(null)} style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.9)", zIndex: 9999, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
          <img src={lightbox.url} alt={lightbox.caption} style={{ maxWidth: "90vw", maxHeight: "85vh", borderRadius: 16, objectFit: "contain" }} />
          {lightbox.caption && <div style={{ position: "absolute", bottom: 30, left: "50%", transform: "translateX(-50%)", color: "#fff", fontSize: 14, fontWeight: 600, textAlign: "center" }}>{lightbox.caption}</div>}
          <button onClick={() => setLightbox(null)} style={{ position: "absolute", top: 20, right: 20, background: "rgba(255,255,255,0.2)", border: "none", borderRadius: "50%", width: 40, height: 40, color: "#fff", fontSize: 18, cursor: "pointer" }}>Γ£ò</button>
        </div>
      )}

      {/* Add Photo Modal */}
      {showModal && (
        <div onClick={() => setShowModal(false)} style={{ position: "fixed", inset: 0, background: "rgba(15,23,42,0.55)", zIndex: 9999, display: "flex", alignItems: "center", justifyContent: "center", padding: 16, backdropFilter: "blur(4px)" }}>
          <div onClick={e => e.stopPropagation()} style={{ background: "#fff", borderRadius: 20, padding: 28, width: "100%", maxWidth: 440, boxShadow: "0 32px 80px rgba(0,0,0,0.2)" }}>
            <div style={{ fontSize: 18, fontWeight: 900, color: "#0F172A", marginBottom: 20 }}>≡ƒô╕ Add Photo</div>
            <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
              <div>
                <label style={{ fontSize: 12, fontWeight: 700, color: "#475569", display: "block", marginBottom: 6 }}>Image URL *</label>
                <input value={form.url} onChange={e => setForm(p => ({ ...p, url: e.target.value }))} placeholder="https://example.com/photo.jpg"
                  style={{ width: "100%", padding: "10px 13px", border: "1.5px solid #E2E8F0", borderRadius: 10, fontSize: 14, outline: "none", fontFamily: "inherit", boxSizing: "border-box" }} />
                {form.url && <img src={form.url} alt="" style={{ marginTop: 8, width: "100%", height: 140, objectFit: "cover", borderRadius: 10 }} onError={e => { (e.target as HTMLImageElement).style.display = "none"; }} />}
              </div>
              <div>
                <label style={{ fontSize: 12, fontWeight: 700, color: "#475569", display: "block", marginBottom: 6 }}>Caption</label>
                <input value={form.caption} onChange={e => setForm(p => ({ ...p, caption: e.target.value }))} placeholder="e.g. Balayage transformation"
                  style={{ width: "100%", padding: "10px 13px", border: "1.5px solid #E2E8F0", borderRadius: 10, fontSize: 14, outline: "none", fontFamily: "inherit", boxSizing: "border-box" }} />
              </div>
              <div>
                <label style={{ fontSize: 12, fontWeight: 700, color: "#475569", display: "block", marginBottom: 6 }}>Category</label>
                <select value={form.category} onChange={e => setForm(p => ({ ...p, category: e.target.value }))} style={{ width: "100%", padding: "10px 13px", border: "1.5px solid #E2E8F0", borderRadius: 10, fontSize: 14, outline: "none", fontFamily: "inherit" }}>
                  {CATEGORIES.map(c => <option key={c} value={c} style={{ textTransform: "capitalize" }}>{c}</option>)}
