                  ΓåÉ Back to sign in
                </button>
              </div>
            </form>
          )
        ) : (
          /* ΓöÇΓöÇ Sign In Mode ΓöÇΓöÇ */
          <>
            <form onSubmit={handleLogin}>
              <div style={{ marginBottom: "16px" }}>
                <label style={{ fontSize: "13px", fontWeight: 500, color: "#0F172A", display: "block", marginBottom: "6px" }}>Email address</label>
