                <input type="password" value={password} onChange={e => setPassword(e.target.value)}
                  placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó" required style={inputStyle} />
              </div>
              {/* Forgot password link */}
              <div style={{ textAlign: "right", marginBottom: "20px" }}>
